118→export function createInitialSketchEditorState() {
119→  return {
120→    activeTool: SKETCH_TOOLS.SELECT,
121→    selectedId: null,
122→    selectedType: null,
123→    toolState: {},
124→    modelViewport: { panX: 400, panY: 300, zoom: DEFAULT_SKETCH_ZOOM },
125→    sheetViewport: { panX: 400, panY: 300, zoom: 2.0 },
126→    workspaceMode: 'model',
127→    activeSheetId: null,
128→    activeView: 'top',
129→    activeAssemblyId: null,
130→    showGrid: true,
131→    snapEnabled: true,
132→    statusMessage: null,
133→    emptyStateDismissed: false,
134→    maximizedPanel: null,
135→  };
136→}
137→
138→export function SketchEditorProvider({ children }) {
139→  const [state, dispatch] = useReducer(
140→    sketchEditorReducer,
141→    null,
142→    createInitialSketchEditorState
143→  );
144→
145→  return (
146→    <SketchEditorContext.Provider value={{ state, dispatch }}>
147→      {children}
148→    </SketchEditorContext.Provider>
149→  );
150→}
151→
152→export function useSketchEditor() {
153→  const ctx = useContext(SketchEditorContext);
154→  if (!ctx) throw new Error('useSketchEditor must be used within SketchEditorProvider');
155→  const { state } = ctx;
156→  const viewport = state.workspaceMode === 'sheet' ? state.sheetViewport : state.modelViewport;
157→  return { ...state, viewport, dispatch: ctx.dispatch };
158→}
