676→
677→        {/* Position (skip for dimensions) */}
678→        {!isDimension && (
679→          <PositionSection position={part.position} onUpdate={handlePositionUpdate} />
680→        )}
681→
682→        {/* Dimension-specific fields */}
683→        {isDimension && (
684→          <div className={styles.fieldGroup}>
685→            <span className={styles.groupTitle}>Dimension</span>
686→            <DimensionFields part={part} onUpdate={handleUpdate} dispatch={dispatch} project={project} />
