289→          <button className={styles.addBtn} onClick={handleAddAssembly} aria-label="Add Assembly" title="Add Assembly">+</button>
290→        </div>
291→
292→        <div className={styles.layerList}>
293→          {assemblies.map((asm) => {
294→            const isActive = asm.id === activeAssemblyId;
